from __future__ import annotations

from dataclasses import dataclass
from typing import Final


class CronParseError(ValueError):
    """Raised when a cron expression is invalid."""


@dataclass(frozen=True)
class FieldSpec:
    name: str
    minimum: int
    maximum: int


@dataclass(frozen=True)
class ParsedField:
    spec: FieldSpec
    raw: str
    values: tuple[int, ...]

    @property
    def is_wildcard(self) -> bool:
        return self.values == tuple(range(self.spec.minimum, self.spec.maximum + 1))

    @property
    def single_value(self) -> int | None:
        return self.values[0] if len(self.values) == 1 else None


@dataclass(frozen=True)
class CronSchedule:
    minute: ParsedField
    hour: ParsedField
    day_of_month: ParsedField
    month: ParsedField
    day_of_week: ParsedField

    def describe(self) -> str:
        if all(
            field.is_wildcard
            for field in (
                self.minute,
                self.hour,
                self.day_of_month,
                self.month,
                self.day_of_week,
            )
        ):
            return "Every minute"

        if (
            self.minute.raw.startswith("*/")
            and self.hour.is_wildcard
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        ):
            step = self.minute.raw.split("/", 1)[1]
            return f"Every {step} minutes"

        if (
            self.hour.raw.startswith("*/")
            and self.minute.single_value == 0
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        ):
            step = self.hour.raw.split("/", 1)[1]
            return f"Every {step} hours, on the hour"

        time = describe_time(self.hour, self.minute)
        day_part = describe_day_part(self.day_of_month, self.month, self.day_of_week)

        return f"{time}{day_part}"


MINUTE: Final = FieldSpec("minute", 0, 59)
HOUR: Final = FieldSpec("hour", 0, 23)
DAY_OF_MONTH: Final = FieldSpec("day_of_month", 1, 31)
MONTH: Final = FieldSpec("month", 1, 12)
DAY_OF_WEEK: Final = FieldSpec("day_of_week", 0, 6)

DAY_NAMES: Final = {
    0: "Sunday",
    1: "Monday",
    2: "Tuesday",
    3: "Wednesday",
    4: "Thursday",
    5: "Friday",
    6: "Saturday",
}


def parse_cron(expression: str) -> CronSchedule:
    fields = expression.split()

    if len(fields) != 5:
        raise CronParseError(
            f"Expected 5 fields: minute hour day_of_month month day_of_week; "
            f"got {len(fields)}"
        )

    minute, hour, day_of_month, month, day_of_week = fields

    return CronSchedule(
        minute=parse_field(minute, MINUTE),
        hour=parse_field(hour, HOUR),
        day_of_month=parse_field(day_of_month, DAY_OF_MONTH),
        month=parse_field(month, MONTH),
        day_of_week=parse_field(day_of_week, DAY_OF_WEEK),
    )


def parse_field(raw: str, spec: FieldSpec) -> ParsedField:
    if not raw:
        raise CronParseError(f"{spec.name} field cannot be empty")

    values: set[int] = set()

    for item in raw.split(","):
        if not item:
            raise CronParseError(f"Empty list item in {spec.name} field: {raw!r}")

        values.update(parse_field_item(item, spec))

    return ParsedField(spec=spec, raw=raw, values=tuple(sorted(values)))


def parse_field_item(item: str, spec: FieldSpec) -> set[int]:
    base, step = split_step(item, spec)

    if base == "*":
        start = spec.minimum
        end = spec.maximum
    elif "-" in base:
        start, end = parse_range(base, spec)
    else:
        start = end = parse_number(base, spec)

    return set(range(start, end + 1, step))


def split_step(item: str, spec: FieldSpec) -> tuple[str, int]:
    if "/" not in item:
        return item, 1

    parts = item.split("/")

    if len(parts) != 2 or not parts[0] or not parts[1]:
        raise CronParseError(f"Invalid step syntax in {spec.name} field: {item!r}")

    step = parse_positive_int(parts[1], f"step in {spec.name} field")

    if step <= 0:
        raise CronParseError(f"Step must be greater than 0 in {spec.name} field")

    return parts[0], step


def parse_range(raw: str, spec: FieldSpec) -> tuple[int, int]:
    parts = raw.split("-")

    if len(parts) != 2 or not parts[0] or not parts[1]:
        raise CronParseError(f"Invalid range in {spec.name} field: {raw!r}")

    start = parse_number(parts[0], spec)
    end = parse_number(parts[1], spec)

    if start > end:
        raise CronParseError(
            f"Range start must be <= range end in {spec.name} field: {raw!r}"
        )

    return start, end


def parse_number(raw: str, spec: FieldSpec) -> int:
    value = parse_positive_int(raw, spec.name)

    if value < spec.minimum or value > spec.maximum:
        raise CronParseError(
            f"{spec.name} value {value} is out of range "
            f"({spec.minimum}-{spec.maximum})"
        )

    return value


def parse_positive_int(raw: str, label: str) -> int:
    if not raw.isdigit():
        raise CronParseError(f"Expected integer for {label}: {raw!r}")

    return int(raw)


def describe_time(hour: ParsedField, minute: ParsedField) -> str:
    if hour.single_value is None or minute.single_value is None:
        return describe_recurring_time(hour, minute)

    if hour.single_value == 0 and minute.single_value == 0:
        return "At midnight"

    return f"At {hour.single_value:02d}:{minute.single_value:02d}"


def describe_recurring_time(hour: ParsedField, minute: ParsedField) -> str:
    if minute.single_value == 0 and not hour.is_wildcard:
        return f"On the hour during {describe_values(hour)}"

    if hour.is_wildcard and not minute.is_wildcard:
        return f"At minute {describe_values(minute)} of every hour"

    return f"At minute {describe_values(minute)} during hour {describe_values(hour)}"


def describe_day_part(
    day_of_month: ParsedField,
    month: ParsedField,
    day_of_week: ParsedField,
) -> str:
    parts: list[str] = []

    if not day_of_month.is_wildcard:
        parts.append(f"on the {describe_ordinals(day_of_month.values)}")

    if not month.is_wildcard:
        parts.append(f"in month {describe_values(month)}")

    if not day_of_week.is_wildcard:
        parts.append(f"on {describe_weekdays(day_of_week.values)}")

    if not parts:
        return ""

    return " " + ", ".join(parts)


def describe_weekdays(values: tuple[int, ...]) -> str:
    if is_contiguous(values):
        return f"{DAY_NAMES[values[0]]} through {DAY_NAMES[values[-1]]}"

    return join_english([DAY_NAMES[value] for value in values])


def describe_ordinals(values: tuple[int, ...]) -> str:
    return join_english([ordinal(value) for value in values])


def describe_values(field: ParsedField) -> str:
    if is_contiguous(field.values):
        return f"{field.values[0]} through {field.values[-1]}"

    return join_english([str(value) for value in field.values])


def is_contiguous(values: tuple[int, ...]) -> bool:
    return len(values) > 1 and values == tuple(range(values[0], values[-1] + 1))


def join_english(items: list[str]) -> str:
    if len(items) == 1:
        return items[0]

    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


if __name__ == "__main__":
    examples = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]

    for expression in examples:
        schedule = parse_cron(expression)
        print(f"{expression!r} -> {schedule.describe()}")
